signature.raw:
VkResult vkCreateShadersEXT(
 VkDevice device,
 uint32_t createInfoCount,
 const VkShaderCreateInfoEXT* pCreateInfos,
 const VkAllocationCallbacks* pAllocator,
 VkShaderEXT* pShaders);

details.example:
VkDevice device = VK_NULL_HANDLE;
uint32_t createInfoCount = 0;
VkShaderCreateInfoEXT createInfos = {};
createInfos.sType = VK_STRUCTURE_TYPE_SHADER_CREATE_INFO_EXT;
VkAllocationCallbacks allocator = {};
VkShaderEXT shaders = VK_NULL_HANDLE;

VkResult result = vkCreateShadersEXT(
 device,
 createInfoCount,
 &createInfos,
 &allocator,
 &shaders
);

